INSERT INTO "titles" ("title_id", "name", "description", "display_format") VALUES (1, '掌管万物', '神', '{name}');
INSERT INTO "titles" ("title_id", "name", "description", "display_format") VALUES (2, '过路的术士', '向伟大的BOSS献上狗粮，然后获得了一人之下万人之上的名头，说是这么说了，但谁信呢？', '{name}');
INSERT INTO "titles" ("title_id", "name", "description", "display_format") VALUES (3, '白金之父', '它允许你使用这个称号的唯一原因是你的生杀大权都还掌握在它手里。', '{name}');
INSERT INTO "titles" ("title_id", "name", "description", "display_format") VALUES (4, '无敌豌豆大王', '豌豆上贡特级犬粮后获得的特殊职称，具有唯一性、高级性、自定义性与噱头性。', '{name}');
INSERT INTO "titles" ("title_id", "name", "description", "display_format") VALUES (5, '鱼甄选CEO', '鱼甄选只把这名号颁给交付过珍品的客户。它不折算凭证，不打折，不找零，没权力没薪水没持股，只证明您确实见过大场面。', '{name}');
INSERT INTO "titles" ("title_id", "name", "description", "display_format") VALUES (6, '观测锚点', '为便于运输免费提供鱼类隔离舱，但无法保障碳基肢体的时空连续性。回收价将视当前维度稳定性收取稳定税与观测费。', '{name}');
INSERT INTO "titles" ("title_id", "name", "description", "display_format") VALUES (7, '万机之神', '回收目标：自成长AI-WL-GQ型；拟态破解方程式：量子筛选；冲突损毁补贴：无；交换品项：荣耀。', '{name}');
INSERT INTO "titles" ("title_id", "name", "description", "display_format") VALUES (8, '星际收藏', '文明墓碑、恒星雏形、引力异常体、熵增残响。科研与收藏价值极高。提交时请隔离存放。', '{name}');
INSERT INTO "titles" ("title_id", "name", "description", "display_format") VALUES (9, '生态武装·维度防线', '某些文明建造全自动化工厂阻拦外敌的可能性，由该类可能性构成的多种时间线无法直接观测。感谢您的帮助，该项目名将作为名号转让。', '{name}');
INSERT INTO "titles" ("title_id", "name", "description", "display_format") VALUES (10, '天地劫火', '集炎火为灵之生命，热浪蒸腾，海水沸响，自成一座微缩的暴怒天地。', '{name}');
INSERT INTO "titles" ("title_id", "name", "description", "display_format") VALUES (11, '一方霸主', '霸主生灵虎视蠢动，如今在争夺残骸的大战中交汇。', '{name}');
INSERT INTO "titles" ("title_id", "name", "description", "display_format") VALUES (12, '寻龙冢', '曾有一缕不灭残魄，以魂灯盗寿命，以断剑斩仙泪。寻龙之途遥遥，迷失永无天日。', '{name}');
INSERT INTO "titles" ("title_id", "name", "description", "display_format") VALUES (13, '寻天道', '何为道？何为天道？不过万物，不过你我。', '{name}');
INSERT INTO "titles" ("title_id", "name", "description", "display_format") VALUES (14, '存在与不存在之物', '那些只不过是尘埃的鱼类，堆积成了通往深渊的阶梯。', '{name}');
INSERT INTO "titles" ("title_id", "name", "description", "display_format") VALUES (15, '别看了。', '别看了。', '{name}');
INSERT INTO "titles" ("title_id", "name", "description", "display_format") VALUES (16, '吞噬万物', '被死有余辜之物吞噬，然后大汗淋漓地醒来。', '{name}');
INSERT INTO "titles" ("title_id", "name", "description", "display_format") VALUES (17, '创造万物', '那是起源者，又或只是破坏者？', '{name}');
INSERT INTO "titles" ("title_id", "name", "description", "display_format") VALUES (18, '白金之剑', '此称号证明你的鱼竿将为善龙神巴哈姆特而挥动，从此与五色龙种不共戴天。', '{name}');
INSERT INTO "titles" ("title_id", "name", "description", "display_format") VALUES (19, '五彩之爪', '此称号证明你的鱼竿将为邪龙神提亚马特而挥动，从此与金属龙种不共戴天。', '{name}');
INSERT INTO "titles" ("title_id", "name", "description", "display_format") VALUES (20, '至高妖精', '此称号证明你的鱼竿将为妖精王而挥动，从此……开始看善邪龙打架的好戏。', '{name}');
INSERT INTO "titles" ("title_id", "name", "description", "display_format") VALUES (21, '元素后裔', '此称号证明你的鱼竿将为……算了，四元素都还打得不可开交呢。', '{name}');
