INSERT INTO "titles" ("title_id", "name", "description", "display_format") VALUES (33, '预知者', '知道得越多就越无力。', NULL);
INSERT INTO "titles" ("title_id", "name", "description", "display_format") VALUES (34, '踏时者', '走得越快就越苍老。', NULL);
INSERT INTO "titles" ("title_id", "name", "description", "display_format") VALUES (35, '污染者', '亵渎得越深就越快乐。', NULL);
INSERT INTO "titles" ("title_id", "name", "description", "display_format") VALUES (36, '献祭者', '献祭之深刻让人沉溺其中。', NULL);
